"""Shared helpers for benchmark report output tests."""

from __future__ import annotations

import importlib.util
import sys
from collections.abc import Generator
from contextlib import contextmanager
from pathlib import Path
from types import ModuleType

_BENCHMARK_PATH = Path(__file__).resolve().parents[2] / "benchmarks" / "benchmark.py"
_REPORTING_PATH = Path(__file__).resolve().parents[2] / "benchmarks" / "reporting.py"
_GENERATE_BENCHMARK_DOCS_PATH = (
    Path(__file__).resolve().parents[2] / "benchmarks" / "generate_docs.py"
)
_GENERATED_BENCHMARK_MARKER = (
    "<!-- Generated by pandas-booster benchmark.py; safe to overwrite/delete. -->"
)


def _expected_benchmark_report_aggs() -> tuple[str, ...]:
    return (
        "sum",
        "mean",
        "median",
        "prod",
        "std",
        "var",
        "min",
        "max",
        "count",
    )


def _generated_markdown(body: str) -> str:
    return f"{_GENERATED_BENCHMARK_MARKER}\n\n{body.rstrip()}\n"


@contextmanager
def _loaded_benchmark_module() -> Generator[ModuleType, None, None]:
    sys_path_snapshot = list(sys.path)
    try:
        spec = importlib.util.spec_from_file_location("benchmark_under_test", _BENCHMARK_PATH)
        assert spec is not None
        assert spec.loader is not None
        module = importlib.util.module_from_spec(spec)
        spec.loader.exec_module(module)
        yield module
    finally:
        sys.path[:] = sys_path_snapshot


@contextmanager
def _loaded_generate_benchmark_docs_module() -> Generator[ModuleType, None, None]:
    spec = importlib.util.spec_from_file_location(
        "generate_benchmark_docs_under_test", _GENERATE_BENCHMARK_DOCS_PATH
    )
    assert spec is not None
    assert spec.loader is not None
    module = importlib.util.module_from_spec(spec)
    spec.loader.exec_module(module)
    yield module


def _make_result(benchmark_module, *, preset: str, agg: str, sort: bool) -> dict:
    stats = benchmark_module.BenchmarkStats(mean=0.1, std=0.01, min=0.09, max=0.11, samples=[0.1])
    return {
        "preset": preset,
        "n_rows": 1_000,
        "n_keys": 1,
        "key_cols": ["key"],
        "combo_cardinality": 100,
        "group_ratio": 0.1,
        "agg": agg,
        "sort": sort,
        "backends": {
            "pandas": {
                "cold_stats": stats,
                "warm_stats": stats,
                "cold_correctness": "not_checked",
                "warm_correctness": "not_checked",
            },
            "booster": {
                "cold_stats": stats,
                "warm_stats": stats,
                "cold_correctness": "pass",
                "warm_correctness": "pass",
            },
        },
    }


def _make_breakdown(
    benchmark_module, *, execution: str = "booster->rust.groupby_std_f64_sorted"
) -> dict:
    stats = benchmark_module.compute_stats([0.1])
    return {
        "execution": execution,
        "phases": {
            "prepare_inputs_s": stats,
            "local_build_s": stats,
            "merge_s": stats,
            "reorder_s": stats,
            "materialize_s": stats,
            "python_normalize_s": stats,
            "python_series_build_s": stats,
            "rust_total_s": stats,
            "python_total_s": stats,
            "total_pipeline_s": stats,
        },
        "rust_total_s": 0.1,
        "python_total_s": 0.1,
        "total_pipeline_s": 0.1,
        "partial_group_total": 1,
        "final_group_count": 1,
        "partial_to_final_ratio": 1.0,
    }
